{
var input = inputs.Length > 0 ? inputs[0] : null;
if (input is null)
    return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

var hueShift = GetFloat(parameters, "hueShift", 0f);
var saturation = GetFloat(parameters, "saturation", 1f);
var lightness = GetFloat(parameters, "lightness", 1f);

var result = input.Clone();

result.Apply((r, g, b, a) =>
{
    // RGB -> HSL
    var max = MathF.Max(r, MathF.Max(g, b));
    var min = MathF.Min(r, MathF.Min(g, b));
    var delta = max - min;

    var h = 0f;
    var s = 0f;
    var l = (max + min) * 0.5f;

    if (delta > 0.0001f)
    {
        s = l <= 0.5f ? delta / (max + min) : delta / (2f - max - min);

        if (MathF.Abs(max - r) < 0.0001f)
            h = ((g - b) / delta + (g < b ? 6f : 0f)) / 6f;
        else if (MathF.Abs(max - g) < 0.0001f)
            h = ((b - r) / delta + 2f) / 6f;
        else
            h = ((r - g) / delta + 4f) / 6f;
    }

    // Apply adjustments
    h = (h + hueShift / 360f) % 1f;
    if (h < 0f) h += 1f;
    s = Math.Clamp(s * saturation, 0f, 1f);
    l = Math.Clamp(l * lightness, 0f, 1f);

    // HSL -> RGB
    if (s < 0.0001f)
    {
        r = l;
        g = l;
        b = l;
    }
    else
    {
        var hue2Rgb = (float p, float q, float t) =>
        {
            if (t < 0f) t += 1f;
            if (t > 1f) t -= 1f;
            if (t < 1f / 6f) return p + (q - p) * 6f * t;
            if (t < 1f / 2f) return q;
            if (t < 2f / 3f) return p + (q - p) * (2f / 3f - t) * 6f;
            return p;
        };

        var q2 = l < 0.5f ? l * (1f + s) : l + s - l * s;
        var p2 = 2f * l - q2;

        r = hue2Rgb(p2, q2, h + 1f / 3f);
        g = hue2Rgb(p2, q2, h);
        b = hue2Rgb(p2, q2, h - 1f / 3f);
    }

    r = Math.Clamp(r, 0f, 1f);
    g = Math.Clamp(g, 0f, 1f);
    b = Math.Clamp(b, 0f, 1f);
    return (r, g, b, a);
});

return result;
}
